// Monta 1 mensagem para o cliente e 1 para o barbeiro por agendamento novo.
const norm = (t) => {
  let n = String(t || '').replace(/\D/g, '');
  if (!n) return '';
  if (!n.startsWith('55')) n = '55' + n;   // garante DDI Brasil
  return n;
};
const saida = [];
for (const item of $input.all()) {
  const a = item.json;
  const cliente = norm(a.cliente_tel);
  const barbeiro = norm(a.barbeiro_tel);
  if (cliente) {
    saida.push({ json: { numero: cliente, tipo: 'cliente', mensagem:
      `✅ *Agendamento confirmado!*\n\n` +
      `Olá, ${a.cliente_nome}! Seu horário na *${a.barbearia}* está marcado:\n\n` +
      `✂️ Serviços: ${a.servicos}\n` +
      `👤 Profissional: ${a.barbeiro_nome}\n` +
      `📅 Data: ${a.data_br}\n` +
      `🕐 Horário: ${a.hora_br}\n\n` +
      `Qualquer imprevisto, é só chamar por aqui. Até logo! 🪒` } });
  }
  if (barbeiro) {
    saida.push({ json: { numero: barbeiro, tipo: 'barbeiro', mensagem:
      `📅 *Novo agendamento!*\n\n` +
      `${a.barbeiro_nome}, você tem um novo horário na *${a.barbearia}*:\n\n` +
      `👤 Cliente: ${a.cliente_nome}\n` +
      `✂️ Serviços: ${a.servicos}\n` +
      `📅 Data: ${a.data_br}\n` +
      `🕐 Horário: ${a.hora_br}` } });
  }
}
return saida;
